using Ledgerly.Domain.Entities; using Ledgerly.Domain.Enums; using Ledgerly.Domain.ValueObjects; namespace Ledgerly.Domain.Tests; public class ExpenseTests { static readonly CurrencyCode Usd=new("USD"); static readonly Guid Org=Guid.NewGuid(),Exp=Guid.NewGuid(),Cash=Guid.NewGuid(); [Fact] public void Post_sets_posted(){ var e=new Expense(Org,"Office supplies",new DateOnly(2026,3,1),Usd,Exp,Cash,new Money(50m,Usd),null,null,null); e.Post(0m); Assert.Equal(ExpenseStatus.Posted,e.Status); Assert.Equal(50m,e.TotalAmount.Amount);} [Fact] public void SetReceipt_updates_url(){ var e=new Expense(Org,"Travel",new DateOnly(2026,3,1),Usd,Exp,Cash,new Money(120m,Usd),null,null,null); e.SetReceipt("https://example.com/receipt.pdf"); Assert.Equal("https://example.com/receipt.pdf",e.ReceiptUrl);} }
